        //             "stopPrice": "1.00000",
        //             "symbol": "DOGEUSDT",
        //             "time": 1775732228695,
        //             "timeInForce": "IOC",
        //             "type": "TAKE_PROFIT_MARKET",
        //             "updateTime": 1775732228695,
        //             "workingType": "CONTRACT_PRICE"
        //         }
        //     ]
        //
        return this.parseOrders(response, market, since, limit);
    }

    public override object parseOrder(object order, object market = null)
    {
        //
        // createOrder (spot)
        //     {
        //         "symbol": "DOGEUSDT",
        //         "orderId": 736557215397183592,
        //         "clientOrderId": "c4551206d34641efbeb64abaa066946d",
        //         "transactTime": 1775608924724
        //     }
        //
        // fetchOpenOrders / fetchOrders / fetchOrder (spot)
        //     {
        //         "symbol": "DOGEUSDT",
        //         "orderId": 736800333186991070,
        //         "clientOrderId": "082007092f624a18bb7af2ab42e7c8e8",
        //         "price": "0.08500",
        //         "origQty": "300.0",
        //         "executedQty": "0",
        //         "cummulativeQuoteQty": "0",
        //         "status": "NEW",
        //         "timeInForce": "GTC",
        //         "type": "LIMIT",
        //         "side": "BUY",
        //         "time": 1775666888520,
        //         "updateTime": 1775666888536,
        //         "isWorking": true
        //     }
        //
        // fetchOpenOrders (contract)
        //     {
        //         "avgPrice": "0.00000",
        //         "clientOrderId": "857e1482-3225-44ce-bc0a-947714c5cabc",
        //         "cumQuote": "0",
        //         "executedQty": "0",
        //         "orderId": 737185556881998184,
        //         "origQty": "1400",
        //         "price": "0.05000",
        //         "reduceOnly": false,
        //         "side": "BUY",
        //         "positionSide": "LONG",
        //         "status": "NEW",
        //         "stopPrice": "0",
        //         "symbol": "DOGEUSDT",
        //         "time": 1775758733006,
        //         "timeInForce": "GTC",
        //         "type": "LIMIT",
        //         "updateTime": 1775758733006,
        //         "workingType": "UNKNOWN_PRICE_TYPE"
        //     }
        //
        // fetchOpenOrders (contract-trigger)
        //     {
        //         "algoId": 737074389748547944,
        //         "clientAlgoId": "d574f517-cea5-433e-b029-415590d3bb80",
        //         "algoType": "CONDITIONAL",
        //         "orderType": "STOP_MARKET",
        //         "symbol": "DOGEUSDT",
        //         "side": "SELL",
        //         "positionSide": "LONG",
        //         "timeInForce": "IOC",
        //         "quantity": "100",
        //         "algoStatus": "UNTRIGGERED",
        //         "actualOrderId": 737074043320009064,
        //         "actualPrice": "0.00000",
        //         "triggerPrice": "0.02000",
        //         "price": "0.00000",
        //         "tpTriggerPrice": null,
        //         "tpPrice": null,
        //         "slTriggerPrice": null,
        //         "slPrice": null,
        //         "tpOrderType": null,
        //         "workingType": "CONTRACT_PRICE",
        //         "closePosition": false,
        //         "reduceOnly": true,
        //         "createTime": 1775732228695,
        //         "updateTime": 1775732228695,
        //         "triggerTime": 0
        //     }
        //
        // fetchCanceledAndClosedOrders (swap only)
        //     {
        //         "avgPrice": "0.00000",
        //         "clientOrderId": "7bd80776-0c3f-4ed9-ab9c-a616d66fac5e",
        //         "cumQuote": "0",
        //         "executedQty": "0",
        //         "orderId": 737074389744353640,
        //         "origQty": "100",
        //         "price": "0.00000",
        //         "reduceOnly": true,
        //         "side": "SELL",
        //         "positionSide": "LONG",
        //         "status": "CANCELED",
        //         "stopPrice": "1.00000",
        //         "symbol": "DOGEUSDT",
        //         "time": 1775732228695,
        //         "timeInForce": "IOC",
        //         "type": "TAKE_PROFIT_MARKET",
        //         "updateTime": 1775732228695,
        //         "workingType": "CONTRACT_PRICE"
        //     }
        //
        object errorCode = this.safeString(order, "errorCode");
        object errorMessage = this.safeString(order, "errorMsg");
        if (isTrue(isTrue((!isEqual(errorCode, null))) || isTrue((!isEqual(errorMessage, null)))))
        {
            this.handleOrderOrPositionError(errorCode, errorMessage, order);
        }
        if (isTrue(isEqual(market, null)))
        {
            object marketId = this.safeString(order, "symbol");
            object positionSide = this.safeString(order, "positionSide");
            object marketType = ((bool) isTrue((isEqual(positionSide, null)))) ? "spot" : "swap";
            market = this.safeMarket(marketId, null, null, marketType);
        }
        object timestamp = this.safeIntegerN(order, new List<object>() {"transactTime", "time", "createTime"});
        object rawStatus = this.safeStringLower(order, "status");
        object triggerPrice = this.omitZero(this.safeString2(order, "triggerPrice", "stopPrice"));
        object rawType = this.safeStringUpper2(order, "type", "orderType");
        object takeProfitPrice = null;
        object stopLossPrice = null;
        if (isTrue(isTrue(isEqual(rawType, "TAKE_PROFIT_MARKET")) || isTrue(isEqual(rawType, "TAKE_PROFIT"))))
        {
            takeProfitPrice = triggerPrice;
        } else if (isTrue(isTrue(isTrue(isEqual(rawType, "STOP_LOSS")) || isTrue(isEqual(rawType, "STOP"))) || isTrue(isEqual(rawType, "STOP_MARKET"))))
        {
            stopLossPrice = triggerPrice;
        }
        return this.safeOrder(new Dictionary<string, object>() {
            { "id", this.safeStringN(order, new List<object>() {"orderId", "algoId", "successOrderId"}) },
            { "clientOrderId", this.safeStringN(order, new List<object>() {"clientOrderId", "origClientOrderId", "clientAlgoId"}) },
            { "symbol", this.safeString(market, "symbol") },
            { "type", this.parseOrderType(rawType) },
            { "timeInForce", this.safeString(order, "timeInForce") },
            { "postOnly", null },
            { "reduceOnly", this.safeBool(order, "reduceOnly") },
            { "side", this.safeStringLower(order, "side") },
            { "amount", this.safeString2(order, "origQty", "quantity") },
            { "price", this.safeString(order, "price") },
            { "triggerPrice", triggerPrice },
            { "cost", this.safeString2(order, "cummulativeQuoteQty", "cumQuote") },
            { "filled", this.safeString(order, "executedQty") },
            { "remaining", null },
            { "timestamp", timestamp },
            { "datetime", this.iso8601(timestamp) },
            { "fee", null },
            { "status", this.parseOrderStatus(rawStatus) },
            { "lastTradeTimestamp", null },
            { "lastUpdateTimestamp", this.safeInteger(order, "updateTime") },
            { "average", this.safeString(order, "avgPrice") },
            { "trades", null },
            { "stopLossPrice", stopLossPrice },
            { "takeProfitPrice", takeProfitPrice },
            { "info", order },
        }, market);
    }

    public virtual object parseOrderStatus(object status)
    {
        object statuses = new Dictionary<string, object>() {
            { "new", "open" },
            { "partial_fill", "closed" },
            { "full_fill", "closed" },
            { "filled", "closed" },
            { "cancelled", "canceled" },
            { "canceled", "canceled" },
            { "rejected", "rejected" },
            { "untriggered", "open" },
        };
        return this.safeString(statuses, status, status);
    }

    public virtual object parseOrderType(object type)
    {
        object types = new Dictionary<string, object>() {
            { "LIMIT", "limit" },
            { "MARKET", "market" },
            { "STOP_LOSS", "limit" },
            { "STOP", "limit" },
            { "TAKE_PROFIT", "limit" },
            { "TAKE_PROFIT_MARKET", "market" },
            { "STOP_MARKET", "market" },
        };
        return this.safeString(types, type, type);
    }

    public virtual void handleOrderOrPositionError(object errorCode, object errorMessage, object order)
    {
        if (isTrue(isEqual(errorCode, null)))
        {
            errorCode = "";
        }
        if (isTrue(isEqual(errorMessage, null)))
        {
            errorMessage = "";
        }
        if (isTrue(isTrue((isEqual(errorCode, ""))) && isTrue((isEqual(errorMessage, "")))))
        {
            // some endpoints could return an empty string if there is no error
            return;
        }
        object feedback = add(add(this.id, " "), this.json(order));
        this.throwExactlyMatchedException(getValue(this.exceptions, "exact"), errorMessage, feedback);
        this.throwExactlyMatchedException(getValue(this.exceptions, "exact"), errorCode, feedback);
        this.throwBroadlyMatchedException(getValue(this.exceptions, "broad"), errorMessage, feedback);
        this.throwBroadlyMatchedException(getValue(this.exceptions, "broad"), errorCode, feedback);
        throw new InvalidOrder ((string)feedback) ;
    }

