    public override object parsePosition(object position, object market = null)
    {
        //
        //     {
        //         "id": 737191855967437160,
        //         "asset": "USDT",
        //         "symbol": "DOGEUSDT",
        //         "side": "LONG",
        //         "marginType": "CROSSED",
        //         "separatedMode": "COMBINED",
        //         "separatedOpenOrderId": 0,
        //         "leverage": "20.00",
        //         "size": "300",
        //         "openValue": "27.96900",
        //         "openFee": "0.02237520",
        //         "fundingFee": "0",
        //         "marginSize": "100",
        //         "isolatedMargin": "0",
        //         "isAutoAppendIsolatedMargin": false,
        //         "cumOpenSize": "300",
        //         "cumOpenValue": "27.96900",
        //         "cumOpenFee": "0.02237520",
        //         "cumCloseSize": "0",
        //         "cumCloseValue": "0",
        //         "cumCloseFee": "0",
        //         "cumFundingFee": "0",
        //         "cumLiquidateFee": "0",
        //         "createdMatchSequenceId": 5762536243,
        //         "updatedMatchSequenceId": 5762741613,
        //         "createdTime": 1775760234825,
        //         "updatedTime": 1775763170789,
        //         "unrealizePnl": "0.00600",
        //         "liquidatePrice": "0"
        //     }
        //
        // watchPoisions
        //     {
        //         "id": "739004481374519656",
        //         "coin": "USDT",
        //         "symbol": "DOGEUSDT",
        //         "side": "LONG",
        //         "marginMode": "CROSSED",
        //         "separatedMode": "COMBINED",
        //         "separatedOpenOrderId": "0",
        //         "leverage": "11",
        //         "size": "100",
        //         "openValue": "9.31100",
        //         "openFee": "0.00744880",
        //         "fundingFee": "0",
        //         "isolatedMargin": "0",
        //         "autoAppendIsolatedMargin": false,
        //         "cumOpenSize": "100",
        //         "cumOpenValue": "9.31100",
        //         "cumOpenFee": "0.00744880",
        //         "cumCloseSize": "0",
        //         "cumCloseValue": "0",
        //         "cumCloseFee": "0",
        //         "cumFundingFee": "0",
        //         "cumLiquidateFee": "0",
        //         "createdMatchSequenceId": "5792711540",
        //         "updatedMatchSequenceId": "5792711540",
        //         "createdTime": "1776192398399",
        //         "updatedTime": "1776192398399"
        //     }
        //
        object errorMessage = this.safeString(position, "errorMsg");
        object errorCode = this.safeString(position, "errorCode");
        if (isTrue(!isEqual(errorMessage, null)))
        {
            this.handleOrderOrPositionError(errorCode, errorMessage, position);
        }
        object marketId = this.safeString(position, "symbol");
        market = this.safeMarket(marketId, market, null, "contract");
        object timestamp = this.safeInteger(position, "createdTime");
        object marginType = this.safeString2(position, "marginType", "marginMode");
        object marginMode = "cross";
        if (isTrue(isEqual(marginType, "ISOLATED")))
        {
            marginMode = "isolated";
        }
        object separatedMode = this.safeString(position, "separatedMode");
        object hedged = null;
        if (isTrue(isEqual(separatedMode, "COMBINED")))
        {
            hedged = false;
        } else if (isTrue(isEqual(separatedMode, "SEPARATED")))
        {
            hedged = true;
        }
        return this.safePosition(new Dictionary<string, object>() {
            { "symbol", getValue(market, "symbol") },
            { "id", this.safeString2(position, "id", "positionId") },
            { "timestamp", timestamp },
            { "datetime", this.iso8601(timestamp) },
            { "contracts", this.safeNumber(position, "size") },
            { "contractSize", null },
            { "side", this.safeStringLower(position, "side") },
            { "notional", this.safeNumber(position, "openValue") },
            { "leverage", this.safeNumber(position, "leverage") },
            { "unrealizedPnl", this.safeNumber(position, "unrealizePnl") },
            { "realizedPnl", null },
            { "collateral", null },
            { "entryPrice", null },
            { "markPrice", null },
            { "liquidationPrice", this.safeNumber(position, "liquidatePrice") },
            { "marginMode", marginMode },
            { "hedged", hedged },
            { "maintenanceMargin", null },
            { "maintenanceMarginPercentage", null },
            { "initialMargin", this.safeNumber(position, "marginSize") },
            { "initialMarginPercentage", null },
            { "marginRatio", null },
            { "lastUpdateTimestamp", this.safeInteger(position, "updatedTime") },
            { "lastPrice", null },
            { "stopLossPrice", null },
            { "takeProfitPrice", null },
            { "percentage", null },
            { "info", null },
        });
    }

